/**
 * font-picker.test.ts — Testes dos helpers puros do FontPicker e componentes
 *
 * Testa funções de formatação, preview e helpers do TextEffectsPanel e StylePresetsBar.
 */

import {
  formatWeight,
  buildPreviewFontFamily,
  createDefaultConfig,
} from '@/components/editor/FontPicker';
import {
  createDefaultShadow,
  createDefaultOutline,
  createDefaultGradient,
  collectActiveEffects,
} from '@/components/editor/TextEffectsPanel';
import {
  presetPreviewLabel,
  presetPreviewStyle,
} from '@/components/editor/StylePresetsBar';
import { POPULAR_FONTS, STYLE_PRESETS } from '@/lib/typography/font-manager';
import type { TextShadowEffect, TextOutlineEffect, TextGradientEffect } from '@/lib/typography/font-manager';

// ─── FontPicker helpers ───────────────────────────────────────────

describe('formatWeight', () => {
  it('formata 100 como Thin', () => {
    expect(formatWeight(100)).toBe('Thin');
  });

  it('formata 400 como Regular', () => {
    expect(formatWeight(400)).toBe('Regular');
  });

  it('formata 700 como Bold', () => {
    expect(formatWeight(700)).toBe('Bold');
  });

  it('formata 900 como Black', () => {
    expect(formatWeight(900)).toBe('Black');
  });

  it('formata 200 como Extra Light', () => {
    expect(formatWeight(200)).toBe('Extra Light');
  });

  it('formata 300 como Light', () => {
    expect(formatWeight(300)).toBe('Light');
  });

  it('formata 500 como Medium', () => {
    expect(formatWeight(500)).toBe('Medium');
  });

  it('formata 600 como Semi Bold', () => {
    expect(formatWeight(600)).toBe('Semi Bold');
  });

  it('formata 800 como Extra Bold', () => {
    expect(formatWeight(800)).toBe('Extra Bold');
  });
});

describe('buildPreviewFontFamily', () => {
  it('envolve o nome em aspas duplas', () => {
    expect(buildPreviewFontFamily('Roboto')).toContain('"Roboto"');
  });

  it('inclui fallback', () => {
    expect(buildPreviewFontFamily('Roboto')).toContain('sans-serif');
  });

  it('inclui monospace fallback para fonte mono', () => {
    expect(buildPreviewFontFamily('Fira Code')).toContain('monospace');
  });
});

describe('createDefaultConfig', () => {
  it('cria config com weight 400 se disponível', () => {
    const font = POPULAR_FONTS.find((f) => f.family === 'Roboto')!;
    const config = createDefaultConfig(font);
    expect(config.family).toBe('Roboto');
    expect(config.weight).toBe(400);
    expect(config.style).toBe('normal');
    expect(config.size).toBe(16);
  });

  it('usa primeiro weight se 400 não disponível', () => {
    const font = POPULAR_FONTS.find((f) => f.family === 'Bebas Neue')!;
    const config = createDefaultConfig(font);
    expect(config.weight).toBe(font.weights[0]);
  });
});

// ─── TextEffectsPanel helpers ─────────────────────────────────────

describe('createDefaultShadow', () => {
  it('retorna shadow com tipo shadow', () => {
    const s = createDefaultShadow();
    expect(s.type).toBe('shadow');
    expect(typeof s.offsetX).toBe('number');
    expect(typeof s.offsetY).toBe('number');
    expect(typeof s.blur).toBe('number');
    expect(typeof s.color).toBe('string');
  });
});

describe('createDefaultOutline', () => {
  it('retorna outline com tipo outline', () => {
    const o = createDefaultOutline();
    expect(o.type).toBe('outline');
    expect(typeof o.width).toBe('number');
    expect(typeof o.color).toBe('string');
  });
});

describe('createDefaultGradient', () => {
  it('retorna gradient com tipo gradient', () => {
    const g = createDefaultGradient();
    expect(g.type).toBe('gradient');
    expect(typeof g.startColor).toBe('string');
    expect(typeof g.endColor).toBe('string');
    expect(['horizontal', 'vertical', 'diagonal']).toContain(g.direction);
  });
});

describe('collectActiveEffects', () => {
  const shadow: TextShadowEffect = { type: 'shadow', offsetX: 1, offsetY: 1, blur: 2, color: '#000' };
  const outline: TextOutlineEffect = { type: 'outline', width: 1, color: '#000' };
  const gradient: TextGradientEffect = {
    type: 'gradient',
    startColor: '#000',
    endColor: '#FFF',
    direction: 'horizontal',
  };

  it('retorna vazio quando nada ativo', () => {
    expect(collectActiveEffects(false, shadow, false, outline, false, gradient)).toHaveLength(0);
  });

  it('inclui apenas shadow quando ativo', () => {
    const result = collectActiveEffects(true, shadow, false, outline, false, gradient);
    expect(result).toHaveLength(1);
    expect(result[0].type).toBe('shadow');
  });

  it('inclui todos quando todos ativos', () => {
    const result = collectActiveEffects(true, shadow, true, outline, true, gradient);
    expect(result).toHaveLength(3);
  });

  it('inclui shadow e gradient quando ambos ativos', () => {
    const result = collectActiveEffects(true, shadow, false, outline, true, gradient);
    expect(result).toHaveLength(2);
    expect(result.map((e) => e.type)).toEqual(['shadow', 'gradient']);
  });
});

// ─── StylePresetsBar helpers ──────────────────────────────────────

describe('presetPreviewLabel', () => {
  it('formata label como "weight sizepx"', () => {
    const preset = STYLE_PRESETS[0]; // titulo
    const label = presetPreviewLabel(preset);
    expect(label).toBe(`${preset.config.weight} ${preset.config.size}px`);
  });

  it('cada preset gera label válida', () => {
    for (const preset of STYLE_PRESETS) {
      const label = presetPreviewLabel(preset);
      expect(label).toMatch(/^\d+ \d+px$/);
    }
  });
});

describe('presetPreviewStyle', () => {
  it('retorna objeto com fontFamily', () => {
    const style = presetPreviewStyle(STYLE_PRESETS[0]);
    expect(style).toHaveProperty('fontFamily');
  });

  it('retorna fontWeight do preset', () => {
    const preset = STYLE_PRESETS[0];
    const style = presetPreviewStyle(preset);
    expect(style.fontWeight).toBe(preset.config.weight);
  });

  it('cada preset gera estilo válido', () => {
    for (const preset of STYLE_PRESETS) {
      const style = presetPreviewStyle(preset);
      expect(style).toHaveProperty('fontFamily');
      expect(style).toHaveProperty('fontWeight');
      expect(style).toHaveProperty('fontSize');
    }
  });
});
